def fetch_records(db_url):
    conn = psycopg2.connect(db_url)
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM records')
        return cursor.fetchall()
    except Exception as e:
        logger.error(f'Query failed: {e}')
        return []
    finally:
        conn.close()
